var active = effect("Multi_Parent")("Position");
var influence = effect("Multi_Parent")("Position Influence") / 100;
var parent1 = effect("Multi_Parent")("Parent 1");
var parent2 = effect("Multi_Parent")("Parent 2");

if (active == 0) {
    transform.position;
} else {
    if ((!parent1 || parent1.index == thisLayer.index) && (!parent2 || parent2.index == thisLayer.index)) {
        transform.position;
    } else if (parent1 && parent1.index != thisLayer.index && parent2 && parent2.index != thisLayer.index) {
        linear(influence, 0, 1, parent1.transform.position, parent2.transform.position);
    } else {
        var parentLayer = (parent1 && parent1.index != thisLayer.index) ? parent1 : parent2;
        if (parentLayer) {
            linear(influence, 0, 1, transform.position, parentLayer.transform.position);
        } else {
            transform.position;
        }
    }
}

var active = effect("Multi_Parent")("Scale");
var influence = effect("Multi_Parent")("Scale Influence") / 100;
var parent1Value = effect("Multi_Parent")("Parent 1").index;
var parent2Value = effect("Multi_Parent")("Parent 2").index;
var parent1Layer = (parent1Value && !isNaN(parent1Value) && parent1Value > 0) ? thisComp.layer(parent1Value) : null;
var parent2Layer = (parent2Value && !isNaN(parent2Value) && parent2Value > 0) ? thisComp.layer(parent2Value) : null;
var originalScale = transform.scale;
if (active == 0 || (!parent1Layer && !parent2Layer)) {
    originalScale;
} else {
    var baseParentScale = [100, 100];
    if (parent1Layer) {
        baseParentScale = parent1Layer.transform.scale;
    } else if (parent2Layer) {
        baseParentScale = parent2Layer.transform.scale;
    }
    var targetParentScale = parent2Layer ? parent2Layer.transform.scale : baseParentScale;
    var adjustedScaleX = (originalScale[0] / baseParentScale[0]) * targetParentScale[0];
    var adjustedScaleY = (originalScale[1] / baseParentScale[1]) * targetParentScale[1];
    [
        linear(influence, 0, 1, originalScale[0], adjustedScaleX),
        linear(influence, 0, 1, originalScale[1], adjustedScaleY)
    ];
}

